var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"보고드립니다! 합중국에서 무력 충돌 발생! 공군 기술 연구소와의 교신이 불가능합니다!","JPN":"ご報告します！　合衆国で武力衝突が発生！　空軍技術研究所との交信が不可能です！","ENG":"Reporting, sir! Armed conflict in the States! Communication with the Air Force Research Lab is cut!","TWN":"報告！合眾國發生武力衝突！聯絡不上空軍研究所了！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"현장에서 건축학부, 철학부 확인! 현지의 요원들이 대응 중이지만 피해를 완전히 억제하긴 어려울 전망입니다!","JPN":"現場で建築学部、哲学部を確認！　現地の要員たちが対応にあたっていますが、被害を完全に防ぐことはできないと予想されます！","ENG":"Department of Architecture and Philosophy spotted on field! Our agents have already engaged in combat, but it will be challenging to contain the damage completely!","TWN":"在現場發現建築學院、哲學院的成員！當地的特務正在處理，但估計很難完全控制損失！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"LAKE-4에서 고준위 침식파 감지! 임계점에 도달하여 CSE 레벨 4로……!","JPN":"LAKE-4で高レベルの侵食波を感知！　臨界点に到達し、CSEレベル4に……！","ENG":"Detecting high-level Corruption ray at LAKE-4! Reached critical point to CSE level 4...!","TWN":"在LAKE-4檢測到高危險級侵蝕波！達到臨界點，CSE等級升至4……！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"흠……. 이번 기회에 끝장을 볼 기세로군.","JPN":"ふむ……今回で決着をつけさせんばかりの勢いだな。","ENG":"Hmm... Looks like they are taking this opportunity to really end it.","TWN":"嗯……看這架勢，他們是想趁此機會做個了斷啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이래서야 티타임을 즐길 겨를도 없겠어.","JPN":"これではティータイムを楽しむ暇もなさそうだ。","ENG":"I guess I won't be able to enjoy my tea today.","TWN":"這樣下去，連喝下午茶的時間都沒有了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"법학부의 존재는 확인됐나?","JPN":"法学部の存在は確認したか？","ENG":"Any sight of the Department of Law?","TWN":"確認到法學院的存在了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"자료 분석 결과, 현재까지는 파악된 바 없습니다. 이번 공세에는 가담하지 않은 모양입니다.","JPN":"資料を分析した結果、今現在では何も把握できていません。今回の攻勢には加わっていない様子です。","ENG":"According to our analysis, not yet, sir. We believe that they didn't take part in this attack.","TWN":"資料分析結果顯示，到目前為止還沒確認。他們好像沒有參與這次攻勢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"좋아. 걱정거리는 하나 덜었군.","JPN":"よし。心配事が一つ減ったな。","ENG":"Okay. That's one thing less to worry about.","TWN":"很好。煩心事少了一件。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 네…… 이렇게인가?","JPN":"あ、はい……こうかな？","ENG":"Oh, okay. Like this?","TWN":"啊，是……這樣嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"크리스입니다. 무슨 일이세요?","JPN":"クリスです。どうしたんですか？","ENG":"This is Chris. You called?","TWN":"我是克莉絲，你有什麼事嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 수훈자답게 믿음직스러운 목소리군. 지금 어디쯤인가?","JPN":"はは、受勲者らしい頼もしい声だ。今はどの辺かな？","ENG":"Haha. What a trustworthy voice of a war hero. Where are you right now?","TWN":"哈哈哈，不愧是受勳者，聲音聽起來很可靠呢。你現在在哪裡？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어… 미덥지 못한 목소리겠죠. 전설의 첩보원도 나이는 못 이기나 보죠.","JPN":"は……頼りない声の間違いでしょ。伝説の諜報員も歳には勝てないみたいですね。","ENG":"What...? ”Untrustworthy”, you mean. Guess even a legendary spy can't beat age.","TWN":"呵……應該是不可靠才對吧。看來傳說中的特務，也輸給了歲月呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지금 손님들을 태우고 가는 중이에요.","JPN":"今お客さんたちを乗せて向かっているところです。","ENG":"I'm escorting the guests and heading over.","TWN":"我現在正載著客人過去。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"사실은 국빈으로 대접해 주길래 영영 눌러앉을까 고민했는데요….","JPN":"本当は国賓として迎えてくれるんだから、そのまま居座ろうかとも思いましたけど……","ENG":"You know, I was considering just slacking off because they treat me like a VIP, but...","TWN":"事實上，因為受到了貴賓待遇，所以我也考慮過要不要永遠待在這裡……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"루이제 아주머니가 인질로 잡혀 있는 이상 어쩔 수 없죠.","JPN":"ルイーゼおばさんが人質になっている以上、仕方ないですね。","ENG":"With them taking Louise hostage, I guess I'll have to play by their rules.","TWN":"既然露易絲阿姨被抓做人質，那就沒辦法了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"일이 잘 풀렸나 보군. 다행일세.","JPN":"うまく行ったようだな。何よりだ。","ENG":"I see things are going well. That's a relief.","TWN":"看來事情很順利啊。真是慶幸。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐, 너무 흔쾌히 승낙해 줘서 어리둥절하네요. 사전에 뒷돈이라도 먹인 거 아니에요?","JPN":"まあ、逆にすんなりと承諾してくれて戸惑ってますよ。あらかじめ裏金でも渡してたんじゃないですか？","ENG":"Uh, I'm kinda surprised they readily accepted. Was there a back deal that I'm not aware of?","TWN":"嗯，答應得太爽快了，有點讓人摸不著頭腦呢。是不是事先給賄賂了？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 갑자기 연락이라니, 좋은 소식은 아니려나.","JPN":"それよりいきなり連絡だなんて、いい知らせではなさそうね。","ENG":"Anyway, why the sudden call? Is there good news you want to tell me?","TWN":"話說回來，你突然聯絡我，應該不是好消息吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이거, 단숨에 들켜 버렸군.","JPN":"おっと、バレてしまったか。","ENG":"Haha. You got me.","TWN":"哎呀，一下子就被你發現了呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇지. 조바심 내는 남자는 알기 쉬우니까.","JPN":"まあね。焦る男ってわかりやすいから。","ENG":"Of course. Anxious men are so easy to read.","TWN":"是啊。因為焦慮的男人很好懂。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"합류 시점을 파악해야 하네. 지금 보낸 좌표로 예상 비행 시각을 확인해 주겠나?","JPN":"合流時刻を把握しないといけない。今送った座標で、予想飛行時刻を確認してくれないか？","ENG":"I need to figure out when we'll rendezvous. Could you check the estimated time of arrival for the coordinates I sent?","TWN":"必須掌握會合時間。你能幫忙確認一下，飛到現在發給你的座標的預計抵達時間嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"얼마든지.","JPN":"ええ、もちろん。","ENG":"Sure.","TWN":"非常樂意。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음, 이 거리면 수송기를 타고 가는 편이 더 빠르게 합류하려나?","JPN":"ふーん、この距離だと輸送機で行った方が早く合流できるかな？","ENG":"Hmm... Perhaps taking a transport plane will be faster?","TWN":"嗯，這個距離的話，乘坐運輸機過去可以更快地會合嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"어…… 저기 말이죠, 저는 얼굴 마담 일 마치면 샤레이드로 돌아가는 거 아니었나요?","JPN":"えっと……あのですね、私は看板娘の役割が終わったらシャレードに帰るんじゃなかったんですか？","ENG":"Uh, just one thing... Wasn't I supposed to return to Charade right after this job?","TWN":"噢……那個，我不是完成顏值擔當，就回查雷德嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"전 이미 류드밀라 씨가 맡기고 간 보석들만으로도 과포화 상태거든요…?","JPN":"すでにリュドミラさんから預かった宝石だけでも過飽和状態なんですけど……？","ENG":"I'm already overloaded as it is with all the gems Lyudmila entrusted me with, you know...?","TWN":"光是因為盧德米拉寄存的寶石，我就已經是過飽和狀態了……？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"제 5성급 호텔은? 레스토랑은요?","JPN":"5つ星のホテルは？　レストランは？","ENG":"What about my 5-star hotel? And the restaurant?","TWN":"五星級飯店？餐廳呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"진정하렴. 작전이란 건 원래 처음 계획대로 진행되지 않아.","JPN":"落ち着いて。作戦ってのは元々最初の計画どおりにはいかないものよ。","ENG":"Calm down. Operations don't always go as planned.","TWN":"你冷靜點。作戰本來就不會按照最初的計畫進行。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흐으으으…….","JPN":"うううう……","ENG":"Hnnnngh...","TWN":"嗚嗚嗚嗚……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"난장판이 따로없군요. 휴먼. 휴게실까지 소란스럽습니다.","JPN":"修羅場ですね。ヒューマン。休憩室にまで騒ぎが伝わってきます。","ENG":"What a mess, human. I can hear your noise all the way from the lounge.","TWN":"真是亂七八糟啊，人類。連休息室都鬧哄哄的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으이익! 좀 멈추라니까, 호라이즌!","JPN":"うぐぐっ！　ちょっと止まってよ、ホライズン！","ENG":"Eeeek! Horizon, will you please stop?","TWN":"嗚嗚！快停下，地平線！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"다들 한창 바쁜데 무작정 들어가면 어떡해!","JPN":"みんな忙しいのに、勝手に入っちゃダメ！","ENG":"How can you just barge in like that when everyone's busy?","TWN":"大家都正在忙，你怎麼能隨便進去呢！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"냉각기에 매달리지 마십시오, 레이첼. 그러다 파손되면 감봉입니다.","JPN":"冷却器にすがりつかないでください、レイチェル。それで破損したら減俸です。","ENG":"Stop clinging to my cooling device, Rachel. I'll dock your pay if you break it.","TWN":"請不要掛在冷卻器上，瑞秋。弄壞了就扣你工資。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"쉬는 데 시끄럽게 해서 미안하군. 상황이 상황이라 말이야.","JPN":"休んでいるところ、騒がしくしてすまない。状況が状況なんでな。","ENG":"My apologies for the noise. This is a rather urgent matter.","TWN":"抱歉在你休息的時候打擾你。發生了一些情況。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"바람을 타고 불경한 음률이 들려온다.","JPN":"風に乗って不敬な音律が聞こえてくる。","ENG":"The wind carries a sacrilegious melody.","TWN":"隨風傳來了不敬的音律。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG"},{"id":"L49_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"마에스트로가 그대들의 시설에 모습을 드러냈다고 하더군. 정녕 이대로 방치할 셈인가.","JPN":"マエストロがそなたたちの施設に姿を現したようだな。本当にこのまま放置するつもりか？","ENG":"Word has it that Maestra appeared in your facility. Are you really going to just let her be?","TWN":"聽說指揮家在你們的設施露面了。你真的打算放任不管嗎。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그렇지 않아도 그 일에 대해 논의하려고 했던 참이었지.","JPN":"ちょうどそのことで論議しようとしていたところだ。","ENG":"We were just about to discuss that issue, in fact.","TWN":"你不提我也正要和你討論這件事。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"아가씨께서는 필요한 전력이 모두 합류하기 전까지 대기하라고 하셨네만…….","JPN":"お嬢様は必要な戦力が全員合流するまで待機するように指示されていたが……","ENG":"Ms. Pendragon told us to stay put until all of the necessary forces arrived, however...","TWN":"小姐讓我在需要的戰鬥力全部會合前一直待命……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"세상 일이 우리 편한 대로만 흘러가진 않는 법이거든.","JPN":"世の中は我々の思いどおりに動くものではない。","ENG":"There is no guarantee that the rest of the world will wait for us.","TWN":"但這世上的事不會全都按照我們的心意發展。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"학회라……. 까다로운 녀석들이긴 해.","JPN":"学会か……やかましいやつらではあるね。","ENG":"The Society, eh...? They are a bothersome bunch.","TWN":"學會……確實不好對付。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼 시간이 촉박하지만 조금 거들기로 할까?","JPN":"じゃあ、時間は厳しいけど少しお手伝いしましょうか。","ENG":"Well, then... I know we’re running short on time, but why not help out a bit?","TWN":"雖然時間緊迫，但是我們要不要幫忙呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"최고 단원 중 하나만 날려 버려도 우리에겐 이득이고.","JPN":"首席奏者のうち、一人でもやっつけられたら私たちには得なんだし。","ENG":"Taking down one of the Elite Members alone will turn the tides in our favor.","TWN":"哪怕只是幹掉一個首席成員，對我們也有好處。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 아니…… 그럼 지금 그림자들이 득실거리는 곳에 돌입하자고요?","JPN":"ちょ、ちょっと……じゃあ、今シャドウがうじゃうじゃいるところに突入しようってことですか？","ENG":"W-wait... Are you saying that we're headed straight towards a place full of Shadows?","TWN":"不…你是說……現在你想進入到處都是暗影的地方嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"팔에 깁스도 아직 못 풀었잖아요? 나이도 잡술 만큼 잡수신 분이 너무 충동적인 거 아니에요?","JPN":"腕のギプスもまだ取れてないじゃないですか？　お年寄りが衝動的過ぎませんか？","ENG":"But you haven't even taken off that cast on your arm yet! Don't you think you're acting a little too rashly for your age right now?","TWN":"你胳膊上的石膏都還沒拆呢！都這麼大年紀了，做事會不會太衝動了？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"신사는 언제나 위험 앞에 솔선수범하는 법이라네.","JPN":"紳士は常に危険を前にして自ら手本を示すものだ。","ENG":"In the face of danger, a gentleman always takes the initiative.","TWN":"紳士總是在危險面前以身作則。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"물론 숙녀 분들은 예외지.","JPN":"もちろんレディーの方々は例外だ。","ENG":"Of course, ladies are an exception.","TWN":"當然，淑女們可以例外。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"이번 작전 목표는 어디까지나 학회가 벌이는 의식이 대상이야.","JPN":"今回の作戦の目標は、あくまでも学会が行う儀式がその対象だ。","ENG":"The Society's ritual is the goal of our operation.","TWN":"這次的作戰目標是學會進行的儀式。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"의식을 최대한 지연시켜서 지원군들과 합류할 계획이라네.","JPN":"儀式をなるべく遅延させ、支援軍との合流を狙う。","ENG":"Our plan is to delay it for as long as we can until reinforcements arrive.","TWN":"我打算盡可能地拖延儀式，然後和援軍會合。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"우리를 이용하고 싶다는 말을 뻔뻔스럽게 하는군요.","JPN":"図々しくも私たちを利用したいと言っているわけですね。","ENG":"And you have the audacity to say you want to use us.","TWN":"你竟然厚著臉皮說想利用我們。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"엘리자베스가 누구에게 배웠는지 알겠습니다, 휴먼.","JPN":"エリザベスが誰を見て教わったかよくわかりました、ヒューマン。","ENG":"Now I see where Elizabeth gets that from, human.","TWN":"我知道伊莉莎白是跟誰學的了，人類。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……나는 가겠다. 마에스트로가 손을 잡은 세력이라면 결국 맞붙게 될 터.","JPN":"……我は行こう。マエストロと手を組んだ勢力であるなら、とどのつまりは相手することになるだろう。","ENG":"...I'll go. If they are allies of Maestra, I will eventually face her one day.","TWN":"……我要去。如果是指揮家聯手的勢力，那麼最後也會碰上。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"시무르그의 후예여. 그대는 이 곳에 남아라.","JPN":"シムルグの末裔よ。そなたはこちらに残れ。","ENG":"Heir of Simurgh, you stay here.","TWN":"西摩格的後裔，你留在這裡。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"사태가 악화된다면 그 몸은 필시 이로운 곳에 쓰일지니.","JPN":"事態が悪化する場合、その身体は必ずや有意義なところに用いられるだろう。","ENG":"If the situation worsens, your body will be put to good use.","TWN":"如果事態惡化，你那副身軀必定會用到有利之處。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제 사용처는 제가 정합니다. 발성 기관이 있다고 나오는 대로 떠들지 마십시오.","JPN":"私の使いどころは自分で決めます。発声器官があるからといって、出るに任せてしゃべらないでください。","ENG":"I decide how I will be put to use. Don't blurt out nonsense just because you have a vocal organ.","TWN":"我的用處由我自己決定。不要因為有發聲器官就隨便亂說。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"여기서 전력이 감소하면 이후의 목적 달성에도 악영향을 끼치겠죠.","JPN":"ここで戦力が減少すると、以後の目的達成にも悪影響を及ぼすでしょう。","ENG":"Reducing the forces here may have a negative impact on our future goals.","TWN":"可如果我們的戰鬥力在這裡減少，對達成以後的目的，也會有負面影響吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"다만, 이 기만적인 행위에는 이자를 두둑하게 받아내겠습니다.","JPN":"ただ、この欺瞞的な行為にはそれ相応の利子をつけてもらいます。","ENG":"However, I will have to charge a high interest rate for your deception.","TWN":"而且對於這種欺騙行為，我們也會收取更多利息。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 얼마든지.","JPN":"はは、もちろんだ。","ENG":"Haha! With pleasure.","TWN":"哈哈，隨便你。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼 에스코트해 드리지, 숙녀 분들.","JPN":"それではエスコートしよう、レディーたち。","ENG":"Then, ladies, I shall be your escort.","TWN":"那我給你們帶路吧，淑女們。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};